110	/**
111	 * Background-enrich the draft: for guests we only have an email-derived fallback
112	 * name for (`nameIsFallback`), resolve the real name + photo from the host's Google
113	 * contacts and merge them into the cached draft. Non-destructive — it only rewrites
114	 * cache fields; RosterRow adopts an updated name/photo solely when the host hasn't
115	 * edited that field, so a late resolve never clobbers a live correction. One-shot
116	 * per distinct set of pending guests (cached in the background after the first run).
117	 */
118	export function useResolveGuestNames(draft: DraftResponse | undefined) {
119	  const qc = useQueryClient();
120	  const iCalUid = draft?.iCalUid;
121	  const pending = (draft?.roster ?? [])
122	    .filter((g) => g.nameIsFallback)
123	    .map((g) => g.email.toLowerCase())
124	    .sort();
125	  // Stable key so the effect fires only when the pending set actually changes.
126	  const key = pending.join('|');
127	
128	  // DIAGNOSTIC: what the panel loaded + who needs resolving. Reveals whether the
129	  // resolver even runs (pending non-empty) and whether nameIsFallback is set.
130	  console.log(
131	    '[auxilio] resolve-names: roster',
132	    (draft?.roster ?? []).map((g) => ({ email: g.email, name: g.name, fb: g.nameIsFallback })),
133	    '| pending', pending,
134	  );
135	
136	  useEffect(() => {
137	    if (!iCalUid || pending.length === 0) return;
138	    let cancelled = false;
139	    rpc({ type: 'RESOLVE_GUESTS', emails: pending })
140	      .then((resolved) => {
141	        console.log('[auxilio] resolve-names: RESOLVE_GUESTS returned', resolved);
142	        if (cancelled || !resolved || Object.keys(resolved).length === 0) return;
143	        // Names we upgraded from a fallback → persist them to the engine so the
144	        // materialized PASS + EMAIL use the real name, not the email-derived
145	        // fallback. Resolution is client-side only, so without this the engine's
146	        // stored draft (and thus the sent invite) keeps the trimmed name.
147	        const current = qc.getQueryData<DraftResponse>(['draft', iCalUid]);
148	        const namePatch = (current?.roster ?? [])
149	          .map((g) => {
150	            const name = resolved[g.email.toLowerCase()]?.name;
151	            return g.nameIsFallback && name ? { email: g.email, name } : null;
152	          })
153	          .filter((x): x is { email: string; name: string } => x !== null);
154	
155	        qc.setQueryData<DraftResponse>(['draft', iCalUid], (prev) => {
156	          if (!prev) return prev;
157	          return {
158	            ...prev,
159	            roster: prev.roster.map((g) => {
160	              const hit = resolved[g.email.toLowerCase()];
161	              if (!hit) return g;
162	              // Only FILL a still-fallback name — never overwrite a real or
163	              // host-edited name with a contacts lookup (that late write was the
164	              // "edit reverts" bug). The photo can still upgrade either way.
165	              const fill = g.nameIsFallback;
166	              return {
167	                ...g,
168	                name: fill ? (hit.name ?? g.name) : g.name,
169	                photoUrl: hit.photoUrl ?? g.photoUrl,
170	                nameIsFallback: fill && hit.name ? false : g.nameIsFallback,
171	              };
172	            }),
173	          };
174	        });
175	
176	        if (namePatch.length > 0 && !cancelled) {
177	          rpc({ type: 'DRAFT_PATCH', iCalUid, patch: { guests: namePatch } }).catch(
178	            () => {
179	              /* best-effort: the name is still shown; only persistence failed */
180	            },
181	          );
182	        }
183	      })
184	      .catch(() => {
185	        /* name resolution is best-effort — failures keep the fallback name */
186	      });
187	    return () => {
188	      cancelled = true;
189	    };
190	    // eslint-disable-next-line react-hooks/exhaustive-deps
191	  }, [iCalUid, key]);
192	}
193	
194	/** Merge a returned VisitDraft into the cached DraftResponse (keep extras). */
195	function mergeDraft(
196	  prev: DraftResponse | undefined,
197	  next: VisitDraft,
198	): DraftResponse | undefined {
199	  if (!prev) return prev;
200	  return { ...prev, ...next };
201	}
202	
203	/** Optimistic patch (toggle / name / phone / template / location). */
204	export function usePatchDraft(iCalUid: string | undefined) {
205	  const qc = useQueryClient();
206	  const key = ['draft', iCalUid];
207	  return useMutation({
208	    mutationFn: (patch: DraftPatch) =>
209	      rpc({ type: 'DRAFT_PATCH', iCalUid: iCalUid!, patch }),
210	    onMutate: async (patch) => {
211	      await qc.cancelQueries({ queryKey: key });
212	      const prev = qc.getQueryData<DraftResponse>(key);
213	      if (prev) qc.setQueryData<DraftResponse>(key, applyPatch(prev, patch));
214	      return { prev };
215	    },
216	    onError: (err, _patch, ctx) => {
217	      // On an auth lapse, KEEP the optimistic edit — don't silently discard what the
218	      // host typed. The panel surfaces a reconnect prompt; after re-auth the value is
219	      // still on screen to re-commit/send. Roll back only for genuine (non-auth)
220	      // failures, where the change really didn't take.
221	      if (isAuthError(err)) return;
222	      if (ctx?.prev) qc.setQueryData(key, ctx.prev);
223	    },
224	    onSuccess: (updated, patch) => {
225	      qc.setQueryData<DraftResponse>(key, (prev) => {
226	        const merged = mergeDraft(prev, updated);
227	        if (!merged) return merged;
228	        // The engine echoes the guest's OLD nameIsFallback (patchDraft doesn't clear
229	        // it when a name is set), which would re-arm the contacts resolver to clobber
230	        // the host's name. Keep it cleared client-side for any guest we just named.
231	        const named = new Set(
232	          (patch.guests ?? [])
233	            .filter((g) => typeof g.name === 'string' && g.name.trim())
234	            .map((g) => g.email.toLowerCase()),
235	        );
236	        if (named.size === 0) return merged;
237	        return {
238	          ...merged,
239	          roster: merged.roster.map((g) =>
240	            named.has(g.email.toLowerCase()) ? { ...g, nameIsFallback: false } : g,
241	          ),
242	        };
243	      });
244	    },
245	  });
246	}
247	
248	/** Apply a DraftPatch to a cached DraftResponse for the optimistic view. */
249	function applyPatch(draft: DraftResponse, patch: DraftPatch): DraftResponse {
250	  const roster = draft.roster.map((g) => {
251	    const edit = patch.guests?.find(
252	      (e) => e.email.toLowerCase() === g.email.toLowerCase(),
253	    );
254	    if (!edit) return g;
255	    const next = { ...g, ...stripEmail(edit) };
256	    // A host-typed name is authoritative: stop marking it a fallback so the
257	    // contacts resolver no longer targets it — and changing the fallback set
258	    // cancels any in-flight resolve for this guest (the effect key changes).
259	    if (typeof edit.name === 'string' && edit.name.trim()) next.nameIsFallback = false;
260	    return next;
261	  });
262	  return {
263	    ...draft,
264	    roster,
265	    location: patch.location ?? draft.location,
266	  };
267	}
268	
269	function stripEmail<T extends { email: string }>(e: T): Omit<T, 'email'> {
270	  const { email: _email, ...rest } = e;
271	  return rest;
272	}
273	
274	export function useSend(iCalUid: string | undefined, start?: string, end?: string) {
275	  const qc = useQueryClient();
276	  return useMutation({
277	    mutationFn: () => rpc({ type: 'SEND', iCalUid: iCalUid!, start, end }),
278	    onSuccess: (res) => {
279	      qc.setQueryData<DraftResponse>(['draft', iCalUid], (prev) =>
280	        mergeDraft(prev, res.draft),
281	      );
282	    },
283	  });
284	}
285	
286	export function usePreview(iCalUid: string | undefined) {
287	  return useMutation({
288	    mutationFn: (visitorEmail: string) =>
289	      rpc({ type: 'PREVIEW', iCalUid: iCalUid!, visitorEmail }),
290	  });
291	}
292	
293	/** Upcoming visitor events (the synced magic-address set) for the picker. */
294	export function useVisitorEvents(enabled: boolean) {
295	  return useQuery({
296	    queryKey: ['visitorEvents'],
297	    queryFn: () => rpc({ type: 'LIST_VISITOR_EVENTS' }),
298	    enabled,
299	    staleTime: 30_000,
300	  });
301	}
