  return q ? safeDecode(q) : null;
}

/** Pull unique email-looking strings from text (best-effort guest scrape). */
function extractEmails(text: string): string[] {
  const matches = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) ?? [];
