/** Our own magic mailbox(es); always stripped from attendees. */
function inboxAddresses(): string[] {
  return (process.env.VISITOR_CALENDAR_INBOX_ADDRESS ?? '')
    .split(',')
    .map((a) => a.trim().toLowerCase())
    .filter(Boolean);
}

/** Is this email one of our magic/inbox mailboxes (the marker address, never a real
 *  guest)? Exported so every draft-building path — not just the ingest classifier —
 *  can strip it at a single chokepoint. */
export function isInboxAddress(email: string | undefined): boolean {
  const e = email?.toLowerCase();
  return !!e && inboxAddresses().includes(e);
}

function domainOf(email: string): string {
  return email.split('@')[1]?.toLowerCase() ?? '';
}

