// ── Card helpers ──────────────────────────────────────────

function statusLabel_(g) {
  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled. Toggle on to resend.</font>';
  if (g.include === false) {
    // Internal colleagues are off by default ON PURPOSE — say so instead of a bare
    // "No pass" that reads like something's missing.
    return g.internal
      ? '<font color="#5f6368">Internal</font>'
      : '<font color="#9aa0a6">No pass</font>';
  }
  return '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
}

// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
function buildStatLine_(roster) {
  var total = roster.length;
  var sent = 0, pending = 0, cancelled = 0;
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.status === 'sent') sent++;
    else if (g.status === 'cancelled') cancelled++;
    else if (g.include !== false) pending++;
  }
  var parts = [total + (total === 1 ? ' guest' : ' guests')];
  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
  return parts.join('  ·  ');
}

// The email template currently in effect for the batch: the first included guest's
// chosen template (templates are stored per-guest but picked once for the whole send),
// or '' to let the confirm card pre-select the engine default.
function currentTemplateKey_(roster) {
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.include !== false && g.emailTemplateKey) return g.emailTemplateKey;
  }
  return '';
}

// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
function formatEventSubtitle_(ev) {
  if (!ev.start) return ev.title || '';
  try {
    var d = new Date(ev.start);
    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
    var datePart = day + ', ' + time;
    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
  } catch (err) {
    return ev.title || '';
  }
}

// ── Main card ─────────────────────────────────────────────
function buildVisitorCard_(e) {
  // Fast path: no external guests in the payload → render immediately without any
